import{_ as t,o as r,c as a,a0 as o}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Use the Recycle Bin","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/recycle-bin.md","filePath":"how-to/recycle-bin.md"}'),i={name:"how-to/recycle-bin.md"};function n(s,e,l,h,c,d){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="use-the-recycle-bin" tabindex="-1">Use the Recycle Bin <a class="header-anchor" href="#use-the-recycle-bin" aria-label="Permalink to &quot;Use the Recycle Bin&quot;">​</a></h1><p>The <strong>Recycle Bin</strong> is where deleted kingdoms, alliances, players, events, imports, and results wait before permanent removal. It is the place to review what was deleted, restore it when allowed, or request help when you do not have direct restore rights.</p><blockquote><p>Screenshot placeholder: bin-pagination.png</p></blockquote><p>Before using this page, read <a href="./../reference/soft-delete.html">What &quot;Delete&quot; Really Does</a>. That guide explains the soft-delete idea. This page explains how to work with the bin itself.</p><h2 id="what-you-can-browse-here" tabindex="-1">What you can browse here <a class="header-anchor" href="#what-you-can-browse-here" aria-label="Permalink to &quot;What you can browse here&quot;">​</a></h2><p>The page is split into sections for:</p><ul><li><strong>Kingdoms</strong></li><li><strong>Alliances</strong></li><li><strong>Players</strong></li><li><strong>Events</strong></li><li><strong>Imports</strong></li><li><strong>Results</strong></li></ul><p>Each section works a little like its own mini list.</p><h2 id="find-what-you-need" tabindex="-1">Find what you need <a class="header-anchor" href="#find-what-you-need" aria-label="Permalink to &quot;Find what you need&quot;">​</a></h2><p>For each section, you can:</p><ul><li>search within that item type</li><li>switch page size to <strong>20</strong>, <strong>50</strong>, or <strong>100</strong></li><li>move with <strong>Previous</strong> and <strong>Next</strong></li></ul><p>This is especially useful when you are dealing with a large cleanup batch.</p><h2 id="restore-an-item" tabindex="-1">Restore an item <a class="header-anchor" href="#restore-an-item" aria-label="Permalink to &quot;Restore an item&quot;">​</a></h2><p>If your role has restore permission for that item type:</p><ol><li>Find the deleted record.</li><li>Select <strong>Restore</strong>.</li></ol><p>The item returns to normal views after restoration.</p><h2 id="request-a-restore-instead" tabindex="-1">Request a restore instead <a class="header-anchor" href="#request-a-restore-instead" aria-label="Permalink to &quot;Request a restore instead&quot;">​</a></h2><p>If you can view the bin but cannot restore directly, you may see <strong>Request restore</strong> instead.</p><p>Use that when you want an authorized admin to review the item and bring it back for you.</p><h2 id="purge-warning" tabindex="-1">Purge warning <a class="header-anchor" href="#purge-warning" aria-label="Permalink to &quot;Purge warning&quot;">​</a></h2><p>Some senior roles can also purge items permanently.</p><p>Purge is different from restore:</p><ul><li>restore brings the item back</li><li>purge removes it for good</li></ul><p>Only purge when you are certain the item should never return.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>Search the correct section first so you do not restore the wrong item type.</li><li>Restore before recreating something by hand whenever possible.</li><li>Use the soft-delete reference when you need the bigger picture.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../reference/soft-delete.html">What &quot;Delete&quot; Really Does</a></li><li><a href="./delete-restore-kingdom-alliance.html">Delete &amp; Restore Kingdoms/Alliances</a></li><li><a href="./delete-restore-player.html">Delete &amp; Restore a Player</a></li></ul>',28)])])}const g=t(i,[["render",n]]);export{p as __pageData,g as default};
